    public Object parseAccount(Object account)
    {
        //
        // fetchAccountsV2
        //
        //     {
        //         "id": "XLM",
        //         "name": "XLM Wallet",
        //         "primary": false,
        //         "type": "wallet",
        //         "currency": {
        //             "code": "XLM",
        //             "name": "Stellar Lumens",
        //             "color": "#000000",
        //             "sort_index": 127,
        //             "exponent": 7,
        //             "type": "crypto",
        //             "address_regex": "^G[A-Z2-7]{55}$",
        //             "asset_id": "13b83335-5ede-595b-821e-5bcdfa80560f",
        //             "destination_tag_name": "XLM Memo ID",
        //             "destination_tag_regex": "^[ -~]{1,28}$"
        //         },
        //         "balance": {
        //             "amount": "0.0000000",
        //             "currency": "XLM"
        //         },
        //         "created_at": null,
        //         "updated_at": null,
        //         "resource": "account",
        //         "resource_path": "/v2/accounts/XLM",
        //         "allow_deposits": true,
        //         "allow_withdrawals": true
        //     }
        //
        // fetchAccountsV3
        //
        //     {
        //         "uuid": "11111111-1111-1111-1111-111111111111",
        //         "name": "USDC Wallet",
        //         "currency": "USDC",
        //         "available_balance": {
        //             "value": "0.0000000000000000",
        //             "currency": "USDC"
        //         },
        //         "default": true,
        //         "active": true,
        //         "created_at": "2023-01-04T06:20:06.456Z",
        //         "updated_at": "2023-01-04T06:20:07.181Z",
        //         "deleted_at": null,
        //         "type": "ACCOUNT_TYPE_CRYPTO",
        //         "ready": false,
        //         "hold": {
        //             "value": "0.0000000000000000",
        //             "currency": "USDC"
        //         }
        //     }
        //
        Object active = this.safeBool(account, "active");
        Object currencyIdV3 = this.safeString(account, "currency");
        Object currency = this.safeDict(account, "currency", new java.util.HashMap<String, Object>() {{}});
        Object currencyId = this.safeString(currency, "code", currencyIdV3);
        Object typeV3 = this.safeString(account, "name");
        Object typeV2 = this.safeString(account, "type");
        Object parts = Helpers.split(((String)typeV3), " ");
        final Object finalActive = active;
        return new java.util.HashMap<String, Object>() {{
            put( "id", CoinbaseCore.this.safeString2(account, "id", "uuid") );
            put( "type", ((Helpers.isTrue((!Helpers.isEqual(finalActive, null))))) ? CoinbaseCore.this.safeStringLower(parts, 1) : typeV2 );
            put( "code", CoinbaseCore.this.safeCurrencyCode(currencyId) );
            put( "info", account );
        }};
    }

    /**
     * @method
     * @name coinbase#createDepositAddress
     * @description create a currency deposit address
     * @see https://docs.cdp.coinbase.com/coinbase-app/transfer-apis/onchain-addresses
     * @param {string} code unified currency code of the currency for the deposit address
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object accountId = this.safeString(parameters, "account_id");
            parameters = this.omit(parameters, "account_id");
            if (Helpers.isTrue(Helpers.isEqual(accountId, null)))
            {
                (this.loadAccounts()).join();
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(this.accounts)); i++)
                {
                    Object account = Helpers.GetValue(this.accounts, i);
                    if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(account, "code"), code)) && Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(account, "type"), "wallet"))))
                    {
                        accountId = Helpers.GetValue(account, "id");
                        break;
                    }
                }
            }
            if (Helpers.isTrue(Helpers.isEqual(accountId, null)))
            {
                throw new ExchangeError((String)Helpers.add(Helpers.add(Helpers.add(this.id, " createDepositAddress() could not find the account with matching currency code "), code), ", specify an `account_id` extra param to target specific wallet")) ;
            }
            final Object finalAccountId = accountId;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "account_id", finalAccountId );
            }};
            Object response = (this.v2PrivatePostAccountsAccountIdAddresses(this.extend(request, parameters))).join();
            //
            //     {
            //         "data": {
            //             "id": "05b1ebbf-9438-5dd4-b297-2ddedc98d0e4",
            //             "address": "coinbasebase",
            //             "address_info": {
            //                 "address": "coinbasebase",
            //                 "destination_tag": "287594668"
            //             },
            //             "name": null,
            //             "created_at": "2019-07-01T14:39:29Z",
            //             "updated_at": "2019-07-01T14:39:29Z",
            //             "network": "eosio",
            //             "uri_scheme": "eosio",
            //             "resource": "address",
            //             "resource_path": "/v2/accounts/14cfc769-e852-52f3-b831-711c104d194c/addresses/05b1ebbf-9438-5dd4-b297-2ddedc98d0e4",
            //             "warnings": [
            //                 {
            //                     "title": "Only send EOS (EOS) to this address",
            //                     "details": "Sending any other cryptocurrency will result in permanent loss.",
            //                     "image_url": "https://dynamic-assets.coinbase.com/deaca3d47b10ed4a91a872e9618706eec34081127762d88f2476ac8e99ada4b48525a9565cf2206d18c04053f278f693434af4d4629ca084a9d01b7a286a7e26/asset_icons/1f8489bb280fb0a0fd643c1161312ba49655040e9aaaced5f9ad3eeaf868eadc.png"
            //                 },
            //                 {
            //                     "title": "Both an address and EOS memo are required to receive EOS",
            //                     "details": "If you send funds without an EOS memo or with an incorrect EOS memo, your funds cannot be credited to your account.",
            //                     "image_url": "https://www.coinbase.com/assets/receive-warning-2f3269d83547a7748fb39d6e0c1c393aee26669bfea6b9f12718094a1abff155.png"
            //                 }
            //             ],
            //             "warning_title": "Only send EOS (EOS) to this address",
            //             "warning_details": "Sending any other cryptocurrency will result in permanent loss.",
            //             "destination_tag": "287594668",
            //             "deposit_uri": "eosio:coinbasebase?dt=287594668",
            //             "callback_url": null
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object tag = this.safeString(data, "destination_tag");
            Object address = this.safeString(data, "address");
            return new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "tag", tag );
                put( "address", address );
                put( "network", null );
                put( "info", response );
            }};
        });

    }

