    public Object parseDepositMethodIds(Object ids, Object... optionalArgs)
    {
        Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
        Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(ids)); i++)
        {
            Object id = this.extend(this.parseDepositMethodId(Helpers.GetValue(ids, i)), parameters);
            ((java.util.List<Object>)result).add(id);
        }
        return result;
    }

    public Object parseDepositMethodId(Object depositId)
    {
        return new java.util.HashMap<String, Object>() {{
            put( "info", depositId );
            put( "id", CoinbaseCore.this.safeString(depositId, "id") );
            put( "currency", CoinbaseCore.this.safeString(depositId, "currency") );
            put( "verified", CoinbaseCore.this.safeBool(depositId, "verified") );
            put( "tag", CoinbaseCore.this.safeString(depositId, "name") );
        }};
    }

